return (() => {
  const cleanArg = (v) => { const t = String(v == null ? '' : v).trim(); return /^\{[a-zA-Z0-9_]+\}$/.test(t) ? '' : t; };
  const mode = (cleanArg('{mode}') || 'text').toLowerCase();
  if (mode === 'items') {
    const sel = "main a[href], main button, a[href][aria-label], button[aria-label], [role='button'][aria-label]";
    const nodes = Array.from(document.querySelectorAll(sel));
    const seen = new Set();
    const items = [];
    for (const n of nodes) {
      const href = n.getAttribute('href') || '';
      const aria = n.getAttribute('aria-label') || '';
      const text = (n.innerText || '').trim().slice(0, 200);
      const key = href + '|' + aria + '|' + text;
      if (seen.has(key)) continue;
      seen.add(key);
      if (!aria && !text && !href) continue;
      items.push({ text, href, aria_label: aria });
      if (items.length >= 100) break;
    }
    return { mode, items };
  }
  const main = document.querySelector('main') || document.body;
  const text = (main.innerText || '').trim().slice(0, 20000);
  return { mode, text };
})();
